SELECT variant_id, file_name, file_size
FROM font_variants
WHERE variant_type = 'bold';

SELECT COUNT(*) AS valid_commercial_licenses
FROM font_licenses
WHERE license_type = 'commercial' AND expiration_date > DATE('now');

SELECT COUNT(variant_id) AS variant_count
FROM font_variants
WHERE font_family_id = 1;

SELECT COUNT(usage_id) AS total_usage
FROM font_usage
WHERE project_id = 0 AND variant_id = 0;

SELECT variant_id, MAX(release_date) AS latest_release_date
FROM font_versions
GROUP BY variant_id;

SELECT variant_id, total_downloads
FROM usage_statistics
ORDER BY total_downloads DESC;

SELECT variant_id, total_projects_used
FROM usage_statistics
ORDER BY total_projects_used DESC;

SELECT variant_id, SUM(usage_count) AS total_usage
FROM font_usage
WHERE variant_id = 0;
